import json
import pickle
from typing import Any, Dict, List, Union
from pathlib import Path

def save_preferences(preferences: Dict[str, Any], filepath: Union[str, Path]) -> None:
    """Save user preferences to a file using JSON format for compatibility and performance."""
    try:
        # Convert custom objects to dictionaries for JSON serialization
        def serialize_object(obj):
            if hasattr(obj, '__dict__'):
                return obj.__dict__
            elif hasattr(obj, '__slots__'):
                return {slot: getattr(obj, slot) for slot in obj.__slots__}
            raise TypeError(f"Object of type {type(obj)} is not JSON serializable")
        
        # Serialize the preferences
        serialized_prefs = json.dumps(preferences, default=serialize_object, indent=2)
        
        # Write to file
        with open(filepath, 'w') as f:
            f.write(serialized_prefs)
            
    except Exception as e:
        raise ValueError(f"Failed to save preferences: {str(e)}")

def load_preferences(filepath: Union[str, Path]) -> Dict[str, Any]:
    """Load user preferences from a file with validation."""
    try:
        # Check if file exists
        if not Path(filepath).exists():
            return {}
            
        # Read from file
        with open(filepath, 'r') as f:
            data = f.read()
            
        if not data.strip():
            return {}
            
        # Parse JSON
        preferences = json.loads(data)
        
        # Validate structure
        if not isinstance(preferences, dict):
            raise ValueError("Loaded preferences must be a dictionary")
            
        # Validate types recursively
        def validate_types(obj, path=""):
            if isinstance(obj, dict):
                for key, value in obj.items():
                    if not isinstance(key, str):
                        raise ValueError(f"Dictionary key at {path} must be a string")
                    validate_types(value, f"{path}.{key}")
            elif isinstance(obj, list):
                for i, item in enumerate(obj):
                    validate_types(item, f"{path}[{i}]")
            elif not isinstance(obj, (str, int, float, bool, type(None))):
                raise ValueError(f"Unsupported type {type(obj)} at {path}")
        
        validate_types(preferences)
        return preferences
        
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON in preferences file: {str(e)}")
    except Exception as e:
        raise ValueError(f"Failed to load preferences: {str(e)}")

